#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Enemies;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.Definitions;

namespace MVZ2.GameContent.Stages
{
    public class SpeedUpStageBehaviour : StageBehaviour
    {
        public SpeedUpStageBehaviour(StageDefinition stageDef, float minSpeed = 1, float maxSpeed = 1) : base(stageDef)
        {
            MinSpeed = minSpeed;
            MaxSpeed = maxSpeed;
        }
        public override void PostEnemySpawned(Entity entity)
        {
            base.PostEnemySpawned(entity);
            MinigameEnemySpeedBuff.AddSpeedBuff(entity, MinSpeed, MaxSpeed);
        }
        public float MinSpeed { get; set; } = 1;
        public float MaxSpeed { get; set; } = 1;
    }
}
